import os

def create_recursive_dir(path):
    path = os.path.normpath(path)

    if os.path.exists(path):
        if os.path.isdir(path):
            return
        else:
            raise OSError(f"Cannot create directory '{path}': A file with the same name already exists.")

    parent_dir = os.path.dirname(path)

    if not parent_dir or parent_dir == path:
        os.mkdir(path)
        return

    create_recursive_dir(parent_dir)

    os.mkdir(path)
